import React, { useState } from 'react';
import QuizSetupWizard from './QuizSetupWizard';
import './QuizBoard.css';
import { motion, AnimatePresence } from 'framer-motion';
import Lottie from 'lottie-react';
// TODO: Replace with a real confetti animation if desired
import confettiAnim from '../assets/rocket-lottie.json';

// Demo avatars for role
const avatars = {
  teacher: '🧑‍🏫',
  mentor: '🧑‍💼',
  student: '🧑‍🎓',
};

// Demo color themes for role
const themes = {
  teacher: { bg: '#f8fafc', accent: '#6366f1' },
  mentor: { bg: '#f8fafc', accent: '#6366f1' },
  student: { bg: '#f8fafc', accent: '#6366f1' },
};

// Real: fetch quiz data from FastAPI backend
async function fetchQuiz({ prompt, role, difficulty, num_questions, explanations, useTimeout, timeoutDuration }) {
  const apiUrl = process.env.REACT_APP_API_URL || 'http://localhost:8000';
  const res = await fetch(`${apiUrl}/api/generate-quiz`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ prompt, role, difficulty, num_questions, explanations, useTimeout, timeoutDuration })
  });
  if (!res.ok) {
    throw new Error(`Failed to generate quiz: ${res.status}`);
  }
  const data = await res.json();
  return data;
}

async function submitAnswers({ questions, user_answers }) {
  const apiUrl = process.env.REACT_APP_API_URL || 'http://localhost:8000';
  const res = await fetch(`${apiUrl}/api/submit-answers`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ questions, user_answers })
  });
  if (!res.ok) {
    throw new Error(`Failed to submit answers: ${res.status}`);
  }
  return await res.json();
} 

function QuizBoard({ quiz, onRestart }) {
  // quiz.timeoutDuration and quiz.useTimeout expected
  const [useTimeout, setUseTimeout] = useState(quiz.useTimeout);
  const [timeoutDuration, setTimeoutDuration] = useState(quiz.timeoutDuration || 15);
  const [current, setCurrent] = useState(0);
  const [selected, setSelected] = useState(null);
  const initialAnswers = quiz.questions.map(q => Array.isArray(q.answer) ? [] : null);
const [answers, setAnswers] = useState(initialAnswers);
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [showToast, setShowToast] = useState(false);
  const [outOfTime, setOutOfTime] = useState(false);
  const timerRef = React.useRef();

  React.useEffect(() => {
    if (!useTimeout || results) return;
    setOutOfTime(false);
    let time = timeoutDuration;
    timerRef.current && clearInterval(timerRef.current);
    timerRef.current = setInterval(() => {
      time -= 1;
      if (time <= 0) {
        clearInterval(timerRef.current);
        setOutOfTime(true);
        setTimeout(() => handleNext(true), 1200); // auto-next after showing timeout
      }
    }, 1000);
    return () => clearInterval(timerRef.current);
  }, [current, useTimeout, timeoutDuration, results]);
  const [timer, setTimer] = useState(useTimeout ? timeoutDuration : null);
  const [feedback, setFeedback] = useState(null); // 'correct' | 'wrong' | null
  const [animating, setAnimating] = useState(false);
  const theme = themes[quiz.role] || themes.teacher;
  const avatar = avatars[quiz.role] || avatars.teacher;
  const q = quiz.questions[current];
  const encouragements = [
    "Let's go!",
    "Keep it up!",
    "You're doing great!",
    "Halfway there!",
    "Almost done!"
  ];
  const encouragement = encouragements[Math.floor((current/quiz.questions.length)*encouragements.length)] || '';

  // For confetti
  const getScorePct = () => results ? (results.correct / results.total) : 0;
  const showConfetti = results && getScorePct() >= 0.7;
  const motivational = results ? (
    getScorePct() === 1 ? "🏆 Perfect! You're a quiz master!" :
    getScorePct() >= 0.8 ? "🎉 Great job!" :
    getScorePct() >= 0.6 ? "👏 Good effort!" :
    "💡 Try again for a better score!"
  ) : null;

  // Timer effect
  React.useEffect(() => {
    if (!useTimeout || results) return;
    if (timer === 0) {
      handleNext(true);
      return;
    }
    const interval = setInterval(() => setTimer(t => t-1), 1000);
    return () => clearInterval(interval);
  }, [timer, results, useTimeout]);

  // Sync selected with answers[current] on question change
  React.useEffect(() => {
    setSelected(answers[current]);
  }, [current, answers]);

  React.useEffect(() => {
    if (useTimeout) {
      setTimer(timeoutDuration);
    } else {
      setTimer(null);
    }
    setFeedback(null);
    setAnimating(false);
  }, [current, useTimeout, timeoutDuration]);

  // Handler for user changing timeout option
  const handleTimeoutToggle = (e) => {
    setUseTimeout(e.target.checked);
  };
  const handleTimeoutDurationChange = (e) => {
    let val = Number(e.target.value);
    if (val < 5) val = 5;
    if (val > 120) val = 120;
    setTimeoutDuration(val);
  };

  // Handle answer selection for both single and multi-answer questions
  const handleOption = idx => {
    const q = quiz.questions[current];
    let newValue;
    if (Array.isArray(q.answer)) {
      // Multi-answer: toggle selection
      newValue = Array.isArray(selected) ? (
        selected.includes(idx)
          ? selected.filter(i => i !== idx)
          : [...selected, idx]
      ) : [idx];
    } else {
      newValue = idx;
    }
    setSelected(newValue);
    setAnswers(prev => {
      const updated = [...prev];
      updated[current] = newValue;
      return updated;
    });
  };



  const handleNext = async (timeout=false) => {
    const q = quiz.questions[current];
    let answerToRecord;
    if (timeout) {
      answerToRecord = Array.isArray(q.answer) ? [] : null;
    } else {
      if (Array.isArray(q.answer)) {
        answerToRecord = Array.isArray(selected) ? selected : [];
      } else {
        answerToRecord = typeof selected === 'number' ? selected : null;
      }
    }
    setAnswers(prev => {
      const updated = [...prev];
      updated[current] = answerToRecord;
      return updated;
    });
    // Do NOT reset selected here; only reset on question change
    if (current < quiz.questions.length - 1) {
      setCurrent(current + 1);
    } else {
      setLoading(true);
      setError(null);
      try {
        console.log('Submitting answers:', answers);
        const res = await submitAnswers({ questions: quiz.questions, user_answers: answers });
        console.log('Quiz results:', res);
        setResults(res);
      } catch (err) {
        setError(err.message || 'Failed to submit answers.');
        setShowToast(true);
        setTimeout(() => setShowToast(false), 3000);
      } finally {
        setLoading(false);
      }
    }
  };


  if (loading) return <div className="spinner-container"><div className="spinner"></div><div style={{marginTop:'1rem'}}>Scoring quiz...</div></div>;
  if (error && showToast) return <div className="toast-error">{error}</div>;

  // DEBUG: Show answers array before results
  if (!results) {
    return (
      <>
        <pre style={{background:'#f8fafc',color:'#6366f1',padding:'0.5rem',fontSize:'0.9rem',marginBottom:'1rem'}}>DEBUG answers: {JSON.stringify(answers)}</pre>
        <motion.div className="quiz-board"
          style={{ background: '#fff', minHeight: '500px', borderRadius: '8px', padding: '2rem', margin: '2rem auto', maxWidth: 600, boxShadow: '0 2px 8px rgba(0,0,0,0.08)' }}
          initial={{opacity:0, y:30}}
          animate={{opacity:1, y:0}}
          exit={{opacity:0, y:30}}
          transition={{duration:0.7}}
        >
          {/* Timeout controls above question */}
          <div style={{display:'flex',alignItems:'center',gap:16,marginBottom:16}}>
            <label style={{display:'flex',alignItems:'center',gap:6}}>
              <input type="checkbox" checked={useTimeout} onChange={handleTimeoutToggle} />
              Timeout per question
            </label>
            {useTimeout && (
              <label style={{display:'flex',alignItems:'center',gap:6}}>
                Duration:
                <input
                  type="number"
                  min={5}
                  max={120}
                  value={timeoutDuration}
                  onChange={handleTimeoutDurationChange}
                  style={{width:60}}
                />
                sec
              </label>
            )}
          </div>
          {useTimeout && (
            <div className="quiz-timer">
              <div className="quiz-timer-bar" style={{ width: `${(timer/(timeoutDuration||15))*100}%`, background: timer > 5 ? '#6366f1' : '#ef4444' }} />
              <span style={{ position:'absolute', right:12, top:-22, fontWeight:600, color: timer > 5 ? theme.accent : '#ef4444' }}>{timer}s</span>
            </div>
          )}
          {encouragement && <div className="quiz-encouragement">{encouragement}</div>}
          <div className="quiz-progress" style={{ marginBottom: '1.5rem' }}>
            <span style={{ color: theme.accent, fontWeight: 600 }}>{current + 1}/{quiz.questions.length}</span>
            <motion.div
              className="progress-bar-bg"
              style={{ background: theme.bg, borderRadius: 12, padding: '0.5rem', boxShadow: '0 2px 8px #eee' }}
            >
              <motion.div
                className="progress-bar-fill"
                style={{ width: `${((current + 1) / quiz.questions.length) * 100}%`, background: theme.accent, boxShadow: animating ? '0 0 12px 2px #6366f1' : 'none', transition: 'width 0.4s, box-shadow 0.3s' }}
                animate={{ width: `${((current + 1) / quiz.questions.length) * 100}%` }}
                transition={{ duration: 0.5, type: 'spring' }}
              />
            </motion.div>
          </div>
          <div className="quiz-avatar" style={{ fontSize: '2.5rem', marginBottom: '1rem' }}>{avatar}</div>
          <h3 style={{ color: '#3730a3', textAlign: 'center', marginBottom: '2rem' }}>{q.text}</h3>
          <div className="quiz-options">
            {Array.isArray(q.answer)
              ? q.options.map((opt, i) => (
                  <label key={i} className={`quiz-option${Array.isArray(selected) && selected.includes(i) ? ' selected' : ''}`}
                    style={{display:'flex',alignItems:'center',gap:10,cursor:outOfTime?'not-allowed':'pointer',opacity:outOfTime?0.6:1}}>
                    <input
                      type="checkbox"
                      checked={Array.isArray(selected) && selected.includes(i)}
                      disabled={outOfTime}
                      onChange={()=>!outOfTime && handleOption(i)}
                    />
                    {opt}
                  </label>
                ))
              : q.options.map((opt, i) => (
                  <label key={i} className={`quiz-option${selected===i ? ' selected' : ''}`}
                    style={{display:'flex',alignItems:'center',gap:10,cursor:outOfTime?'not-allowed':'pointer',opacity:outOfTime?0.6:1}}>
                    <input
                      type="radio"
                      name="single-choice"
                      checked={selected===i}
                      disabled={outOfTime}
                      onChange={()=>!outOfTime && handleOption(i)}
                    />
                    {opt}
                  </label>
                ))}
          </div>
          {outOfTime && <div className="quiz-feedback timeout">⏰ Out of time! No answer selected.</div>}
          <motion.button
            className={`quiz-next${
              (Array.isArray(q.answer)
                ? Array.isArray(selected) && selected.length > 0
                : selected !== null) && !feedback && !animating
                ? ' animated'
                : ''
            }`}
            onClick={handleNext}
            disabled={
              (Array.isArray(q.answer)
                ? !Array.isArray(selected) || selected.length === 0
                : selected === null) || feedback || animating || outOfTime
            }
            style={{
              background: '#6366f1',
              opacity:
                (Array.isArray(q.answer)
                  ? !Array.isArray(selected) || selected.length === 0
                  : selected === null) || feedback || animating || outOfTime
                  ? 0.5
                  : 1,
              pointerEvents:
                (Array.isArray(q.answer)
                  ? !Array.isArray(selected) || selected.length === 0
                  : selected === null) || feedback || animating || outOfTime
                  ? 'none'
                  : 'auto',
            }}
            whileHover={{
              scale:
                (Array.isArray(q.answer)
                  ? Array.isArray(selected) && selected.length > 0
                  : selected !== null) && !feedback && !animating && !outOfTime
                  ? 1.06
                  : 1,
            }}
            whileTap={{ scale: 0.97 }}
            transition={{ type: 'spring', stiffness: 350 }}
          >
            Next
          </motion.button>
        </motion.div>
      </>
    );
  }
  if (results) {
    return (
      <motion.div className="quiz-results" style={{ background: theme.bg, borderRadius: '24px', padding: '2rem', margin: '2rem auto', maxWidth: 500 }}
        initial={{opacity:0, y:30}}
        animate={{opacity:1, y:0}}
        exit={{opacity:0, y:30}}
        transition={{duration:0.7}}
      >
        <div style={{display:'flex', alignItems:'center', gap:16}}>
          <span style={{fontSize:'2.5rem'}}>{avatar}</span>
          <h2 style={{ color: '#3730a3', margin:0 }}>Quiz Results</h2>
        </div>
        {showConfetti && <Lottie animationData={confettiAnim} loop={false} autoplay style={{width:120,margin:'0 auto'}} />}
        <div style={{ margin: '1rem 0', fontWeight: 600, fontSize:'1.2rem', color: '#3730a3' }}>
          Score: {results.correct} / {results.total}
        </div>
        <div style={{fontWeight:600, fontSize:'1.1rem', color:'#3730a3', marginBottom:12}}>{motivational}</div>
        <ul style={{ listStyle: 'none', padding: 0 }}>
          {results.results.map((r, idx) => (
            <motion.li key={idx} style={{ marginBottom: '1.5rem', background: '#fff', borderRadius: 12, padding: '1rem', boxShadow: '0 2px 8px #eee' }}
              initial={{opacity:0, y:30}} animate={{opacity:1, y:0}} transition={{duration:0.5, delay:idx*0.1}}
            >
              <div style={{ fontWeight: 600 }}>{idx + 1}. {r.question}</div>
              <div>Your answer: <span style={{ color: r.correct ? 'green' : 'red', fontWeight: 600 }}>
                {Array.isArray(r.user_answer)
                  ? (r.user_answer && r.user_answer.length > 0 && r.user_answer.every(i => typeof i === 'number' && quiz.questions[idx].options[i] !== undefined)
                      ? r.user_answer.map(i => quiz.questions[idx].options[i]).join(', ')
                      : 'No answer')
                  : (typeof r.user_answer === 'number' && quiz.questions[idx].options[r.user_answer] !== undefined
                      ? quiz.questions[idx].options[r.user_answer]
                      : 'No answer')}
              </span></div>
              <div>Correct answer: <span style={{ color: 'green', fontWeight: 600 }}>
                {Array.isArray(r.correct_answer)
                  ? (r.correct_answer && r.correct_answer.length > 0 && r.correct_answer.every(i => typeof i === 'number' && quiz.questions[idx].options[i] !== undefined)
                      ? r.correct_answer.map(i => quiz.questions[idx].options[i]).join(', ')
                      : 'No answer')
                  : (typeof r.correct_answer === 'number' && quiz.questions[idx].options[r.correct_answer] !== undefined
                      ? quiz.questions[idx].options[r.correct_answer]
                      : 'No answer')}
              </span></div>
              {r.explanation && (
                <div style={{ fontStyle: 'italic', marginTop: 4, color: '#555' }}>Explanation: {r.explanation}</div>
              )}
            </motion.li>
          ))}
        </ul>
        <button onClick={onRestart} style={{ background: '#6366f1', color: '#fff', border: 'none', borderRadius: 4, padding: '0.75rem 1.5rem', fontWeight: 600, marginTop: 16 }}>Restart Quiz</button>
      </motion.div>
    );
  }

  return (
    <>
      <motion.div className="quiz-board"
        style={{ background: '#fff', minHeight: '500px', borderRadius: '8px', padding: '2rem', margin: '2rem auto', maxWidth: 600, boxShadow: '0 2px 8px rgba(0,0,0,0.08)' }}
        initial={{opacity:0, y:30}}
        animate={{opacity:1, y:0}}
        exit={{opacity:0, y:30}}
        transition={{duration:0.7}}
      >
        {/* Timeout controls above question */}
        <div style={{display:'flex',alignItems:'center',gap:16,marginBottom:16}}>
          <label style={{display:'flex',alignItems:'center',gap:6}}>
            <input type="checkbox" checked={useTimeout} onChange={handleTimeoutToggle} />
            Timeout per question
          </label>
          {useTimeout && (
            <label style={{display:'flex',alignItems:'center',gap:6}}>
              Duration:
              <input
                type="number"
                min={5}
                max={120}
                value={timeoutDuration}
                onChange={handleTimeoutDurationChange}
                style={{width:60}}
              />
              sec
            </label>
          )}
        </div>
        {useTimeout && (
          <div className="quiz-timer">
            <div className="quiz-timer-bar" style={{ width: `${(timer/(timeoutDuration||15))*100}%`, background: timer > 5 ? '#6366f1' : '#ef4444' }} />
            <span style={{ position:'absolute', right:12, top:-22, fontWeight:600, color: timer > 5 ? theme.accent : '#ef4444' }}>{timer}s</span>
          </div>
        )}
        {encouragement && <div className="quiz-encouragement">{encouragement}</div>}
        <div className="quiz-progress" style={{ marginBottom: '1.5rem' }}>
          <span style={{ color: theme.accent, fontWeight: 600 }}>{current + 1}/{quiz.questions.length}</span>
          <motion.div
            className="progress-bar-bg"
            style={{ background: theme.bg, borderRadius: 12, padding: '0.5rem', boxShadow: '0 2px 8px #eee' }}
          >
            <motion.div
              className="progress-bar-fill"
              style={{ width: `${((current + 1) / quiz.questions.length) * 100}%`, background: theme.accent, boxShadow: animating ? '0 0 12px 2px #6366f1' : 'none', transition: 'width 0.4s, box-shadow 0.3s' }}
              animate={{ width: `${((current + 1) / quiz.questions.length) * 100}%` }}
              transition={{ duration: 0.5, type: 'spring' }}
            />
          </motion.div>
        </div>
        <div className="quiz-avatar" style={{ fontSize: '2.5rem', marginBottom: '1rem' }}>{avatar}</div>
        <h3 style={{ color: '#3730a3', textAlign: 'center', marginBottom: '2rem' }}>{q.text}</h3>
        <div className="quiz-options">
          {Array.isArray(q.answer)
            ? q.options.map((opt, i) => (
                <label key={i} className={`quiz-option${Array.isArray(selected) && selected.includes(i) ? ' selected' : ''}`}
                  style={{display:'flex',alignItems:'center',gap:10,cursor:outOfTime?'not-allowed':'pointer',opacity:outOfTime?0.6:1}}>
                  <input
                    type="checkbox"
                    checked={Array.isArray(selected) && selected.includes(i)}
                    disabled={outOfTime}
                    onChange={e => {
                      if (outOfTime) return;
                      let arr = Array.isArray(selected) ? [...selected] : [];
                      if (e.target.checked) {
                        arr.push(i);
                      } else {
                        arr = arr.filter(idx => idx !== i);
                      }
                      setSelected(arr);
                    }}
                  />
                  {opt}
                </label>
              ))
            : q.options.map((opt, i) => (
                <label key={i} className={`quiz-option${selected===i ? ' selected' : ''}`}
                  style={{display:'flex',alignItems:'center',gap:10,cursor:outOfTime?'not-allowed':'pointer',opacity:outOfTime?0.6:1}}>
                  <input
                    type="radio"
                    name="single-choice"
                    checked={selected===i}
                    disabled={outOfTime}
                    onChange={()=>!outOfTime && setSelected(i)}
                  />
                  {opt}
                </label>
              ))}
        </div>
        {outOfTime && <div className="quiz-feedback timeout">⏰ Out of time! No answer selected.</div>}
        <motion.button
          className={`quiz-next${
            (Array.isArray(q.answer)
              ? Array.isArray(selected) && selected.length > 0
              : selected !== null) && !feedback && !animating
              ? ' animated'
              : ''
          }`}
          onClick={handleNext}
          disabled={
            (Array.isArray(q.answer)
              ? !Array.isArray(selected) || selected.length === 0
              : selected === null) || feedback || animating || outOfTime
          }
          style={{
            background: '#6366f1',
            opacity:
              (Array.isArray(q.answer)
                ? !Array.isArray(selected) || selected.length === 0
                : selected === null) || feedback || animating || outOfTime
                ? 0.5
                : 1,
            pointerEvents:
              (Array.isArray(q.answer)
                ? !Array.isArray(selected) || selected.length === 0
                : selected === null) || feedback || animating || outOfTime
                ? 'none'
                : 'auto',
          }}
          whileHover={{
            scale:
              (Array.isArray(q.answer)
                ? Array.isArray(selected) && selected.length > 0
                : selected !== null) && !feedback && !animating && !outOfTime
                ? 1.06
                : 1,
          }}
          whileTap={{ scale: 0.97 }}
          transition={{ type: 'spring', stiffness: 350 }}
        >
          Next
        </motion.button>
      </motion.div>
    </>
  );
}

function QuizBuilder() {
  const [quiz, setQuiz] = useState(null);
  const [quizSetupParams, setQuizSetupParams] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleGenerate = async params => {
    setLoading(true);
    setError(null);
    setQuizSetupParams(params); // Save for passing to QuizBoard
    try {
      const data = await fetchQuiz(params);
      // Attach timeout settings to quiz object for QuizBoard
      setQuiz({ ...data, useTimeout: params.useTimeout, timeoutDuration: params.timeoutDuration });
    } catch (err) {
      setError(err.message || 'Failed to generate quiz.');
    } finally {
      setLoading(false);
    }
  };
  const handleRestart = () => setQuiz(null);

  if (loading) return <div style={{textAlign:'center',marginTop:'2rem'}}>Generating quiz...</div>;
  if (error) return <div style={{color:'red',textAlign:'center',marginTop:'2rem'}}>{error}</div>;

  return quiz ? (
    <QuizBoard quiz={quiz} onRestart={handleRestart} />
  ) : (
    <QuizSetupWizard onGenerate={handleGenerate} />
  );
}

export default QuizBuilder;
